impl Xmalloc {
    pub fn gl_attribute_pure<T>(value: T) -> T;

    pub fn xmalloc(size: usize) -> Vec<u8>;
    pub fn ximalloc(size: usize) -> Vec<u8>;
    pub fn xcharalloc(size: usize) -> String;

    pub fn xrealloc(buffer: Vec<u8>, new_size: usize) -> Vec<u8>;
    pub fn xirealloc(buffer: Vec<u8>, new_size: usize) -> Vec<u8>;
    pub fn xreallocarray(buffer: Vec<u8>, n: usize, elem_size: usize) -> Vec<u8>;
    pub fn xireallocarray(buffer: Vec<u8>, n: usize, elem_size: usize) -> Vec<u8>;

